// Para cada booking expirado, monta payload para deletar Calendar + notificar Telegram.
function utcToBRT(isoString) {
  if (!isoString) return '';
  try {
    const dt = new Date(isoString);
    if (isNaN(dt.getTime())) return isoString;
    const brtTime = new Date(dt.getTime() - 3 * 60 * 60 * 1000);
    const dias = ['domingo', 'segunda', 'terca', 'quarta', 'quinta', 'sexta', 'sabado'];
    const dayName = dias[brtTime.getUTCDay()];
    const dd = String(brtTime.getUTCDate()).padStart(2, '0');
    const mm = String(brtTime.getUTCMonth() + 1).padStart(2, '0');
    const hh = String(brtTime.getUTCHours()).padStart(2, '0');
    const min = String(brtTime.getUTCMinutes()).padStart(2, '0');
    const timeStr = min === '00' ? hh + 'h' : hh + 'h' + min;
    return dayName + ', ' + dd + '/' + mm + ' as ' + timeStr;
  } catch(e) { return isoString; }
}

const out = [];
for (const item of $input.all()) {
  const e = item.json;
  if (!e.booking_id) continue;
  const slotBrt = utcToBRT(e.proposed_slot_start);
  out.push({
    json: {
      booking_id: e.booking_id,
      tenant_id: e.tenant_id,
      clinic_name: e.clinic_name,
      patient_phone: e.patient_phone,
      patient_name: e.patient_name,
      telegram_chat_id: e.telegram_chat_id,
      calendar_id: e.calendar_id,
      calendar_event_id: e.original_calendar_event_id,
      telegram_msg: '*Proposta de reagendamento expirou*\n\n' +
        'Clinica: ' + (e.clinic_name || e.tenant_id) + '\n' +
        'Paciente: ' + (e.patient_name || e.patient_phone) + '\n' +
        'Horario proposto: ' + slotBrt + '\n\n' +
        'Paciente nao respondeu em 24h. O slot foi liberado e a consulta foi cancelada. ' +
        'Se quiser tentar de novo, abra a agenda e proponha um novo horario.',
    },
  });
}
return out;

